fn url_encode_filter(s: &str) -> String {
    s.replace('{', "%7B")
     .replace('}', "%7D")
     .replace('"', "%22")
     .replace('[', "%5B")
     .replace(']', "%5D")
     .replace(':', "%3A")
     .replace('=', "%3D")
     .replace(' ', "%20")
     .replace('&', "%26")
}
